Phoneme::Id ContextPhonology::PhonemeInContext::phoneme(s16 pos) const {

: if (pos == 0)

  : return [phoneme];

  else if (pos > 0) {
  : if (u16(pos - 1) < [context].future.length())

    : return [context].future[pos - 1];

    else

    : return Phoneme::term;

  } else { verify(pos < 0);
  : if (u16(-1 - pos) < [context].history.length())

    : return [context].history[-1 - pos];

    else

    : return Phoneme::term;

  }

}

